   121			summary.UpdatedAt = rec.ObservedAt
   122			if rec.Unit != "" {
   123				summary.Unit = rec.Unit
   124			}
   125		}
   126		summary.Count = len(history)
   127		summary.Average = sum / float64(len(history))
