   131	func (s *Store) LoadDefinition(metricID string) (Definition, error) {
   132		if s.execStore == nil {
   133			return Definition{}, fmt.Errorf("metric store is not initialized")
   134		}
   135		defs, err := s.execStore.ListDefinitions(metricID)
   136		if err != nil {
   137			return Definition{}, err
   138		}
   139		var (
   140			best  Definition
   141			found bool
   142		)
   143		for _, def := range defs {
   144			if def.ID == "" {
   145				continue
   146			}
   147			mapped, err := metricDefinitionFromExec(def)
   148			if err != nil {
   149				return Definition{}, err
   150			}
   151			if mapped.MetricID != metricID || !mapped.Active {
   152				continue
   153			}
   154			if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
   155				best = mapped
   156				found = true
   157			}
   158		}
   159		if !found {
   160			return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
   161		}
   162		if best.DefinitionID == "" {
   163			return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
   164		}
   165		return best, nil
   166	}
