   217	func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
   218		switch against {
   219		case "", "latest":
   220			return history[len(history)-1], nil
   221		case "baseline":
   222			return history[0], nil
   223		default:
   224			for _, rec := range history {
   225				if rec.RunID == against {
